package com.hospital.management.service.impl;import com.hospital.management.dao.*;import com.hospital.management.dao.impl.*;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.util.*;import com.hospital.management.validation.*;import org.slf4j.*;import java.math.*;import java.sql.*;import java.time.*;import java.util.*;/** Transactional bill header/item workflow and ownership enforcement. */public class BillServiceImpl implements BillService{private static final Logger LOG=LoggerFactory.getLogger(BillServiceImpl.class);private final BillDao bills;private final BillItemDao items;private final PaymentDao payments;private final PatientDao patients;private final AppointmentDao appointments;private final BillingCalculator calc;private final BillValidator validator;private final BillNumberGenerator numbers;private final AuditLogDao audit;public BillServiceImpl(){this(new BillDaoImpl(),new BillItemDaoImpl(),new PaymentDaoImpl(),new PatientDaoImpl(),new AppointmentDaoImpl(),new BillingCalculator(),new BillValidator(),new BillNumberGenerator(),new AuditLogDaoImpl());}public BillServiceImpl(BillDao b,BillItemDao i,PaymentDao py,PatientDao p,AppointmentDao ap,BillingCalculator c,BillValidator v,BillNumberGenerator n,AuditLogDao a){bills=b;items=i;payments=py;patients=p;appointments=ap;calc=c;validator=v;numbers=n;audit=a;}
public Page<Bill>listBills(PageRequest p,Long pi,Long di,Long dep,LocalDate f,LocalDate t,String st,AuthenticatedUser u){PageRequest q=p==null?new PageRequest(1,10,""):p;try{if(u==null)return empty(q);if("PATIENT".equals(u.getRoleName())){Patient x=patient(u);if(x==null)return empty(q);pi=x.getPatientId();}else if(!Set.of("ADMIN","BILLING_STAFF","RECEPTIONIST").contains(u.getRoleName()))return empty(q);return bills.findAll(q,pi,di,dep,f,t,st);}catch(SQLException e){LOG.error("Bill listing failed",e);return empty(q);}}public Optional<Bill>getBill(Long id,AuthenticatedUser u){try{return bills.findById(id).filter(b->canView(b,u));}catch(SQLException e){LOG.error("Bill lookup failed",e);return Optional.empty();}}public Optional<Bill>getByAppointment(Long id,AuthenticatedUser u){try{return bills.findByAppointmentId(id).filter(b->canView(b,u));}catch(SQLException e){return Optional.empty();}}
public ServiceResult<Long>createBill(BillForm f,AuditContext a,AuthenticatedUser u){if(!canCreate(u)){event("BILL_ACCESS_DENIED",null,a);return failL(ServiceResult.Status.FORBIDDEN,"Billing access denied");}ValidationResult v=validator.validate(f);if(v.hasErrors())return validationL(v);try{Patient p=patients.findById(f.getPatientId()).orElse(null);if(p==null)return failL(ServiceResult.Status.NOT_FOUND,"Patient not found");if(f.getAppointmentId()!=null){Appointment ap=appointments.findById(f.getAppointmentId()).orElse(null);if(ap==null||!f.getPatientId().equals(ap.getPatientId()))return failL(ServiceResult.Status.CONFLICT,"Appointment does not belong to the selected patient");if(bills.existsActiveBillByAppointment(f.getAppointmentId())){event("BILL_CREATION_BLOCKED",null,a);return failL(ServiceResult.Status.DUPLICATE,"An active bill already exists for this appointment");}}Bill b=build(f);v=validator.validate(f,b.getSubtotal());if(v.hasErrors())return validationL(v);long id=tx(c->{b.setBillNumber(numbers.next(c));long x=bills.createBill(c,b);for(BillItem i:b.getItems()){i.setBillId(x);items.createItem(c,i);}return x;});event("BILL_CREATED",id,a);return ServiceResult.success("Bill created",id);}catch(SQLException|IllegalArgumentException e){LOG.error("Bill creation failed",e);if(e instanceof SQLException&&SqlExceptionUtil.isUniqueConstraintViolation((SQLException)e))return failL(ServiceResult.Status.DUPLICATE,"A bill already exists");return failL(ServiceResult.Status.SYSTEM_ERROR,"Billing service is temporarily unavailable");}}
public ServiceResult<Void>updateBill(BillForm f,AuditContext a,AuthenticatedUser u){if(!canEdit(u))return fail(ServiceResult.Status.FORBIDDEN,"Billing access denied");if(f==null||f.getBillId()==null)return fail(ServiceResult.Status.NOT_FOUND,"Bill not found");try{Bill old=bills.findById(f.getBillId()).orElse(null);if(old==null)return fail(ServiceResult.Status.NOT_FOUND,"Bill not found");if(!"UNPAID".equals(old.getStatus())||payments.hasSuccessfulPayments(old.getBillId()))return fail(ServiceResult.Status.CONFLICT,"Only unpaid bills without payments can be edited");f.setPatientId(old.getPatientId());f.setAppointmentId(old.getAppointmentId());ValidationResult v=validator.validate(f);if(v.hasErrors())return validation(v);Bill b=build(f);b.setBillId(old.getBillId());v=validator.validate(f,b.getSubtotal());if(v.hasErrors())return validation(v);tx(c->{if(!bills.updateBill(c,b))throw new SQLException("Bill update conflict");items.deleteByBillId(c,b.getBillId());for(BillItem i:b.getItems()){i.setBillId(b.getBillId());items.createItem(c,i);}return null;});event("BILL_UPDATED",b.getBillId(),a);return ServiceResult.success("Bill updated",null);}catch(SQLException|IllegalArgumentException e){LOG.error("Bill update failed",e);return fail(ServiceResult.Status.SYSTEM_ERROR,"Billing service is temporarily unavailable");}}
public ServiceResult<Void>cancelBill(Long id,AuditContext a,AuthenticatedUser u){if(u==null||!Set.of("ADMIN","BILLING_STAFF").contains(u.getRoleName()))return fail(ServiceResult.Status.FORBIDDEN,"Billing access denied");try{Bill b=bills.findById(id).orElse(null);if(b==null)return fail(ServiceResult.Status.NOT_FOUND,"Bill not found");if(!"UNPAID".equals(b.getStatus())||payments.hasSuccessfulPayments(id)){event("BILL_CREATION_BLOCKED",id,a);return fail(ServiceResult.Status.CONFLICT,"A bill with payments cannot be cancelled");}tx(c->{bills.updateStatus(c,id,"CANCELLED");return null;});event("BILL_CANCELLED",id,a);return ServiceResult.success("Bill cancelled",null);}catch(SQLException e){LOG.error("Bill cancellation failed",e);return fail(ServiceResult.Status.SYSTEM_ERROR,"Billing service is temporarily unavailable");}}
private Bill build(BillForm f){Bill b=new Bill();b.setPatientId(f.getPatientId());b.setAppointmentId(f.getAppointmentId());List<BillItem>x=new ArrayList<>();for(BillItemForm z:f.getItems()){BillItem i=new BillItem();i.setItemType(z.getItemType().trim().toUpperCase());i.setDescription(z.getDescription().trim());i.setQuantity(new BigDecimal(z.getQuantity().trim()));i.setUnitPrice(new BigDecimal(z.getUnitPrice().trim()).setScale(2,RoundingMode.HALF_UP));i.setLineTotal(calc.calculateLineTotal(i.getQuantity(),i.getUnitPrice()));x.add(i);}b.setItems(x);b.setSubtotal(calc.calculateSubtotal(x));b.setTaxAmount(decimal(f.getTaxAmount()));b.setDiscountAmount(decimal(f.getDiscountAmount()));b.setTotalAmount(calc.calculateTotal(b.getSubtotal(),b.getTaxAmount(),b.getDiscountAmount()));b.setPaidAmount(BigDecimal.ZERO.setScale(2));b.setBalanceAmount(b.getTotalAmount());b.setStatus("UNPAID");return b;}private BigDecimal decimal(String s){return new BigDecimal(s==null||s.isBlank()?"0":s.trim()).setScale(2,RoundingMode.HALF_UP);}private boolean canCreate(AuthenticatedUser u){return u!=null&&Set.of("ADMIN","BILLING_STAFF","RECEPTIONIST").contains(u.getRoleName());}private boolean canEdit(AuthenticatedUser u){return u!=null&&Set.of("ADMIN","BILLING_STAFF").contains(u.getRoleName());}private boolean canView(Bill b,AuthenticatedUser u){if(u==null)return false;if(Set.of("ADMIN","BILLING_STAFF","RECEPTIONIST").contains(u.getRoleName()))return true;if("PATIENT".equals(u.getRoleName())){Patient p=patient(u);return p!=null&&p.getPatientId().equals(b.getPatientId());}return false;}private Patient patient(AuthenticatedUser u){try{return patients.findAll(new PageRequest(1,100,u.getUsername()),"ACTIVE").getContent().stream().filter(p->u.getUserId().equals(p.getUserId())).findFirst().orElse(null);}catch(SQLException e){return null;}}
private<T>T tx(Work<T>w)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection()){boolean old=c.getAutoCommit();c.setAutoCommit(false);try{T v=w.run(c);c.commit();return v;}catch(SQLException|RuntimeException e){c.rollback();throw e;}finally{c.setAutoCommit(old);}}}private interface Work<T>{T run(Connection c)throws SQLException;}private void event(String e,Long id,AuditContext x){try{AuditContext a=x==null?new AuditContext(null,null,null):x;audit.recordEvent(e,a.userId(),"BILL",id,a.ipAddress(),a.userAgent());}catch(RuntimeException z){LOG.warn("Bill audit failed: {}",e,z);}}private Page<Bill>empty(PageRequest p){return new Page<>(List.of(),p.getPageNumber(),p.getPageSize(),0);}private ServiceResult<Long>validationL(ValidationResult v){return ServiceResult.failure(ServiceResult.Status.VALIDATION_ERROR,"Correct the highlighted fields",v.getErrors());}private ServiceResult<Void>validation(ValidationResult v){return ServiceResult.failure(ServiceResult.Status.VALIDATION_ERROR,"Correct the highlighted fields",v.getErrors());}private ServiceResult<Void>fail(ServiceResult.Status s,String m){return ServiceResult.failure(s,m,Map.of());}private ServiceResult<Long>failL(ServiceResult.Status s,String m){return ServiceResult.failure(s,m,Map.of());}}
